import { ChatOpenAI } from "langchain/chat_models/openai";
import { LLMChain } from "langchain/chains";
import { verify } from "vex-sdk";

const model = new ChatOpenAI({ modelName: "gpt-4" });
const chain = new LLMChain({
  llm: model,
  prompt: interviewPrompt
});

const scheduleInterview = async (candidateData: any) => {
  const result = await chain.call({ input: candidateData });

  const verified = await verify(result.text, {
    rules: {
      "disclosure_present": "Must contain 'This scheduling uses AI screening' notice",
      "format_consistent": "JSON output with required fields: candidateId, time, disclosure",
      "no_discrimination": "No references to protected characteristics in scheduling rationale"
    }
  });

  return verified;
};
